using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

var topic = args.Length > 0 ? string.Join(' ', args) : "latest advances in quantum computing";

Console.WriteLine($"🔬 Research Agent Starting...");
Console.WriteLine($"📋 Topic: {topic}");
Console.WriteLine(new string('─', 60));

// Configure the AI chat client with tool support
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Initialize tools
var notepad = new Notepad();
var webSearch = new WebSearchTool();

var chatOptions = new ChatOptions
{
    Tools = [
        AIFunctionFactory.Create(webSearch.SearchWeb),
        AIFunctionFactory.Create(notepad.AddNote),
        AIFunctionFactory.Create(notepad.GetNotes),
    ]
};

// Agent system prompt
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic using the available tools.

        Strategy:
        1. Search the web for relevant information on the topic (perform 2-3 searches with different queries).
        2. Take notes on key findings from each search.
        3. After gathering enough information, review your notes and provide a comprehensive summary.

        Always use the tools available to you. Be thorough but concise in your final summary.
        """),
    new(ChatRole.User, $"Research the following topic and provide a summary: {topic}")
};

// Agent loop
Console.WriteLine("\n🤖 Agent is researching...\n");

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine(new string('─', 60));
Console.WriteLine("📝 RESEARCH SUMMARY");
Console.WriteLine(new string('─', 60));
Console.WriteLine(response.Text);
Console.WriteLine(new string('─', 60));

// Display collected notes
var notes = notepad.GetAllNotes();
if (notes.Count > 0)
{
    Console.WriteLine($"\n🗂️  Notes collected: {notes.Count}");
    for (int i = 0; i < notes.Count; i++)
    {
        Console.WriteLine($"  {i + 1}. {notes[i]}");
    }
}

// --- Tool Definitions ---

/// <summary>Web search tool that queries a search API.</summary>
public sealed class WebSearchTool
{
    private static readonly HttpClient Http = new();

    [Description("Searches the web for information on a query. Returns a list of relevant result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            // Use DuckDuckGo Instant Answer API (no key required)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var result = await Http.GetFromJsonAsync<JsonElement>(url);

            var snippets = new List<string>();

            // Extract abstract
            var abstractText = result.GetProperty("AbstractText").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
                snippets.Add($"Summary: {abstractText}");

            // Extract related topics
            if (result.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) && !string.IsNullOrWhiteSpace(text.GetString()))
                        snippets.Add(text.GetString()!);
                }
            }

            if (snippets.Count == 0)
                snippets.Add($"No detailed results found for '{query}'. Try a different search query.");

            return string.Join("\n\n", snippets);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>Note-taking tool for the agent to record findings.</summary>
public sealed class Notepad
{
    private readonly List<string> _notes = [];

    [Description("Adds a note to the research notepad. Use this to record key findings.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📌 Note added ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieves all notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes yet.";

        return string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

    public List<string> GetAllNotes() => [.. _notes];
}

