             // Extract related topics
             if (result.TryGetProperty("RelatedTopics", out var related))
             {
                 foreach (var item in related.EnumerateArray().Take(5))
                 {
                     if (item.TryGetProperty("Text", out var text) && !string.IsNullOrWhiteSpace(text.GetString()))
                         snippets.Add(text.GetString()!);
                 }
             }

             if (snippets.Count == 0)
                 snippets.Add($"No detailed results found for '{query}'. Try a different search query.");

             return string.Join("\n\n", snippets);
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }
 }

 /// <summary>Note-taking tool for the agent to record findings.</summary>
 public sealed class Notepad
 {
     private readonly List<string> _notes = [];

     [Description("Adds a note to the research notepad. Use this to record key findings.")]
     public string AddNote(
         [Description("The note content to save")] string note)
     {
         _notes.Add(note);
         Console.WriteLine($"  📌 Note added ({_notes.Count} total)");
         return $"Note saved. You now have {_notes.Count} note(s).";
     }

     [Description("Retrieves all notes collected so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes yet.";

         return string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
     }

     public List<string> GetAllNotes() => [.. _notes];
 }
